export type Rank = 'G' | 'F' | 'E' | 'D' | 'C' | 'B' | 'A' | 'S';

export interface RankData {
  rank: Rank;
  index: number;
  color: string;
  bgColor: string;
}

export interface FactorCalculationResult {
  steps: number;
  totalFactors: number;
  combination: {
    stars3: number;
    stars2: number;
    stars1: number;
  };
}

import { Rank, RankData } from './types';

export const RANKS: RankData[] = [
  { rank: 'G', index: 0, color: 'text-gray-500', bgColor: 'bg-gray-100' },
  { rank: 'F', index: 1, color: 'text-gray-400', bgColor: 'bg-gray-50' },
  { rank: 'E', index: 2, color: 'text-blue-500', bgColor: 'bg-blue-50' },
  { rank: 'D', index: 3, color: 'text-blue-600', bgColor: 'bg-blue-100' },
  { rank: 'C', index: 4, color: 'text-green-500', bgColor: 'bg-green-100' },
  { rank: 'B', index: 5, color: 'text-yellow-600', bgColor: 'bg-yellow-100' },
  { rank: 'A', index: 6, color: 'text-pink-600', bgColor: 'bg-pink-100' },
  { rank: 'S', index: 7, color: 'text-orange-500', bgColor: 'bg-orange-100' },
];

export const RANK_MAP = RANKS.reduce((acc, curr) => {
  acc[curr.rank] = curr;
  return acc;
}, {} as Record<Rank, RankData>);

export const calculateFactors = (current: Rank, target: Rank): number => {
  const startIndex = RANK_MAP[current].index;
  const targetIndex = RANK_MAP[target].index;
  const steps = targetIndex - startIndex;

  if (steps <= 0) return 0;

  // Rule:
  // 1-3 factors -> +1 rank
  // 4-6 factors -> +2 ranks
  // 7-9 factors -> +3 ranks
  // 10-12 factors -> +4 ranks
  // ... and so on
  // Formula for 'n' rank jumps: 1 + (n-1) * 3
  return 1 + (steps - 1) * 3;
};

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getInheritanceAdvice = async (current: string, target: string, factors: number) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `User is playing Uma Musume Pretty Derby. 
      Their horse aptitude is currently ${current} and they want to upgrade it to ${target}. 
      They need ${factors} factors. 
      Give 3-4 short, professional bullet points in Chinese on how to achieve this effectively using 9-star factors, 
      the importance of red factors (inheritance), and tips for selecting parents/grandparents.`,
      config: {
        temperature: 0.7,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "无法获取AI建议，请检查网络连接。";
  }
};

