import React, { useState, useEffect, useCallback } from 'react';
import { RANKS, calculateFactors } from './constants';
import { Rank } from './types';
import RankBadge from './components/RankBadge';
import { getInheritanceAdvice } from './services/geminiService';

const App: React.FC = () => {
  const [currentRank, setCurrentRank] = useState<Rank>('G');
  const [targetRank, setTargetRank] = useState<Rank>('A');
  const [factorsNeeded, setFactorsNeeded] = useState(0);
  const [advice, setAdvice] = useState<string>('');
  const [loadingAdvice, setLoadingAdvice] = useState(false);

  useEffect(() => {
    const result = calculateFactors(currentRank, targetRank);
    setFactorsNeeded(result);
  }, [currentRank, targetRank]);

  const fetchAdvice = useCallback(async () => {
    setLoadingAdvice(true);
    const result = await getInheritanceAdvice(currentRank, targetRank, factorsNeeded);
    setAdvice(result || '无建议可用');
    setLoadingAdvice(false);
  }, [currentRank, targetRank, factorsNeeded]);

  const handleRankClick = (type: 'current' | 'target', rank: Rank) => {
    if (type === 'current') {
      setCurrentRank(rank);
      // Ensure target is always >= current
      const rankIdx = RANKS.findIndex(r => r.rank === rank);
      const targetIdx = RANKS.findIndex(r => r.rank === targetRank);
      if (targetIdx <= rankIdx && rankIdx < RANKS.length - 1) {
        setTargetRank(RANKS[rankIdx + 1].rank);
      }
    } else {
      const currentIdx = RANKS.findIndex(r => r.rank === currentRank);
      const targetIdx = RANKS.findIndex(r => r.rank === rank);
      if (targetIdx > currentIdx) {
        setTargetRank(rank);
      }
    }
  };

  return (
    <div className="max-w-md mx-auto px-4 py-8 md:py-12">
      <header className="text-center mb-8">
        <div className="inline-block p-2 bg-white rounded-2xl shadow-sm mb-4">
          <img 
            src="https://picsum.photos/seed/uma/200/200" 
            alt="Uma Header" 
            className="w-24 h-24 rounded-xl object-cover"
          />
        </div>
        <h1 className="text-2xl font-bold text-pink-600">赛马娘因子计算器</h1>
        <p className="text-gray-500 text-sm">Uma Musume Factor Calculator</p>
      </header>

      <main className="space-y-6">
        {/* Input Card */}
        <section className="bg-white rounded-3xl shadow-xl p-6 border border-pink-100">
          <div className="space-y-8">
            {/* Current Rank */}
            <div>
              <label className="block text-sm font-semibold text-gray-400 mb-3 uppercase tracking-wider">初始适性 (Current)</label>
              <div className="flex flex-wrap gap-3 justify-center">
                {RANKS.map((r) => (
                  <RankBadge 
                    key={`cur-${r.rank}`}
                    data={r}
                    isSelected={currentRank === r.rank}
                    onClick={() => handleRankClick('current', r.rank)}
                  />
                ))}
              </div>
            </div>

            <div className="flex justify-center py-2">
              <div className="bg-pink-50 rounded-full p-2">
                <i className="fa-solid fa-chevron-down text-pink-400"></i>
              </div>
            </div>

            {/* Target Rank */}
            <div>
              <label className="block text-sm font-semibold text-gray-400 mb-3 uppercase tracking-wider">目标适性 (Target)</label>
              <div className="flex flex-wrap gap-3 justify-center">
                {RANKS.map((r) => (
                  <RankBadge 
                    key={`tar-${r.rank}`}
                    data={r}
                    isSelected={targetRank === r.rank}
                    onClick={() => handleRankClick('target', r.rank)}
                    size="md"
                  />
                ))}
              </div>
            </div>
          </div>
        </section>

        {/* Result Card */}
        <section className="bg-gradient-to-br from-pink-500 to-rose-400 rounded-3xl shadow-xl p-8 text-white text-center transform hover:scale-[1.02] transition-transform">
          <h2 className="text-lg font-medium opacity-90 mb-2">所需因子总数</h2>
          <div className="flex items-center justify-center gap-2 mb-4">
            <span className="text-6xl font-black">{factorsNeeded}</span>
            <span className="text-xl font-bold self-end mb-2">星</span>
          </div>

          <div className="grid grid-cols-2 gap-4 mt-4 text-sm bg-white/10 rounded-2xl p-4">
            <div className="border-r border-white/20">
              <p className="opacity-80">跨越档位</p>
              <p className="text-lg font-bold">
                {RANKS.findIndex(r => r.rank === targetRank) - RANKS.findIndex(r => r.rank === currentRank)} 阶
              </p>
            </div>
            <div>
              <p className="opacity-80">常见组合</p>
              <p className="text-lg font-bold">
                {Math.floor(factorsNeeded / 3)}×3⭐ + {factorsNeeded % 3}⭐
              </p>
            </div>
          </div>

          {targetRank === 'S' && (
            <div className="mt-4 p-2 bg-yellow-400/20 rounded-xl text-xs border border-yellow-400/30">
              提示：S 级无法直接通过初始因子到达，需在育成中继承。
            </div>
          )}
        </section>

        {/* Advice Section */}
        <section className="bg-white rounded-3xl shadow-md p-6">
          <div className="flex items-center justify-between mb-4">
            <h3 className="font-bold text-gray-700 flex items-center gap-2">
              <i className="fa-solid fa-lightbulb text-yellow-500"></i>
              育成建议 (AI)
            </h3>
            <button 
              onClick={fetchAdvice}
              disabled={loadingAdvice}
              className="text-xs bg-pink-100 text-pink-600 px-3 py-1.5 rounded-full hover:bg-pink-200 transition-colors disabled:opacity-50"
            >
              {loadingAdvice ? '计算中...' : '获取攻略'}
            </button>
          </div>

          <div className="min-h-[100px] text-sm text-gray-600 leading-relaxed">
            {advice ? (
              <div className="prose prose-pink whitespace-pre-wrap">
                {advice}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center py-6 text-gray-400 italic">
                <i className="fa-solid fa-robot text-3xl mb-2 opacity-20"></i>
