            )}
          </div>
        </section>

        {/* Info Table */}
        <section className="bg-gray-50 rounded-2xl p-4 text-xs text-gray-500">
          <p className="font-bold mb-2 text-gray-400">因子计算参考表 (1-4-7-10 规则):</p>
          <div className="grid grid-cols-2 gap-y-1">
            <p>1 阶 (如 B→A): 1 因子</p>
            <p>2 阶 (如 C→A): 4 因子</p>
            <p>3 阶 (如 D→A): 7 因子</p>
            <p>4 阶 (如 E→A): 10 因子</p>
            <p>5 阶 (如 F→A): 13 因子</p>
            <p>6 阶 (如 G→A): 16 因子</p>
          </div>
        </section>
      </main>

      <footer className="mt-12 text-center text-gray-400 text-xs pb-8">
        <p>© 2024 Uma Musume Fan Tool. Not affiliated with Cygames.</p>
      </footer>
    </div>
  );
};

export default App;

